import { Component, OnInit } from "@angular/core";
import { FormBuilder, FormGroup, Validators } from "@angular/forms";
import { ChargeMaintenanceService } from "src/app/shared/services/charge-maintenance-service.service";
import { MaintenanceService } from "src/app/shared/services/maintenance.service";
import { ToastService } from "src/app/shared/services/toast.service";

@Component({
  selector: "npr-departmenrt-id-new",
  templateUrl: "./departmenrt-id-new.component.html",
  styleUrls: ["./departmenrt-id-new.component.scss"],
})
export class DepartmenrtIdNewComponent implements OnInit {
  departmentForm: FormGroup;
  submitDisab: boolean;
  respData: any;
  index: number;
  editFlag: boolean = true;

  constructor(
    private toastService: ToastService,
    private formBuilder: FormBuilder,
    private departmentService: MaintenanceService
  ) {}

  ngOnInit(): void {
    this.buildForm("");
    this.departmentService.getIndex().subscribe((index) => {
      if (index.index) {
        this.index = index.index;
        this.departmentService
          .gettingDepartmentDataInSummary()
          .subscribe((dataresp) => {
            console.log(dataresp);
            if (dataresp) {
              this.getRespBasedOnId(dataresp, index.index);
            }
          });
      }
    });
  }
  getRespBasedOnId(resp, arg0) {
    this.respData = resp.find((item) => item.departId == arg0);
    console.log("obj based on departId ", this.respData);
    this.editFlag = false;
    this.buildForm(this.respData);
  }
  buildForm(item) {
    this.departmentForm = this.formBuilder.group({
      departId: [item ? item.departId : "", Validators.required],
      departName: [item ? item.departName : "", [Validators.required]],
      fromSeries: [item ? item.fromSeries : "", Validators.required],
      toSeries: [item ? item.toSeries : "", Validators.required],
      inputBy: [item ? item.inputBy : ""],
      inputTime: [item ? item.inputTime : ""],
      verifiedBy: [item ? item.verifiedBy : ""],
      verifiedTime: [item ? item.verifiedTime : ""],
      recordStatus: [item ? item.recordStatus : ""],
      verifiedOnce: [item ? item.verifiedOnce : ""],
      modNo: [item ? item.modNo : ""],
      verifiedStatus: [item ? item.verifiedStatus : ""],
      respMsg: [item ? item.respMsg : ""],
    });
  }
  onSubmittingofChargeMaintenance(value) {
    if (value === "submit") {
      this.departmentService
        .onSubmittingDepartment(this.departmentForm.value)
        .subscribe((deptMaintenanceResp) => {
          console.log(deptMaintenanceResp);

          if (
            deptMaintenanceResp.respMsg === "Department Saved Successfully "
          ) {
            this.submitDisab = true;
            this.toastService.successMessage(
              "Department Saved Successfully",
              ""
            );
          } else {
            this.toastService.infoMessage(deptMaintenanceResp.respMsg, "");
          }
        });
    }
    if (value === "edit") {

      this.departmentService.onsaveTheEditOfDepartment(this.departmentForm.value).subscribe((deptMaintenanceResp) => {         
        console.log(deptMaintenanceResp);
          if (deptMaintenanceResp) {
            if (deptMaintenanceResp.respMsg === "Modified Record Success") {
              this.submitDisab = true;
              this.respData = deptMaintenanceResp;
              this.toastService.successMessage(
                "Department Updated Successfully",
                ""
              );
            } else {
              this.toastService.infoMessage(deptMaintenanceResp.respMsg, "");
            }
          } 

          else {
            this.toastService.errorMessage("Department Updation failed", "");
          }
        });
    }
  }
  getChargeMaintainenceSummary() {
    this.departmentService
      .gettingDepartmentDataInSummary()
      .subscribe((dataresp) => {
        console.log(dataresp);
        // this.respArray = dataresp;
        // this.dtTrigger.next();
      });
  }
  onAuthorizingTheRecord() {
    console.log("this is authorzation");
    this.departmentService
      .onAuthDepartment(this.departmentForm.value)
      .subscribe((authResp) => {
        console.log(authResp);
        this.respData = authResp;
        if (this.respData) {
          if (this.respData.inputBy != null) {
            this.toastService.successMessage(
              "You authorized the Record!",
              ""
              // type: "success"
            );
          } else {
            this.toastService.errorMessage(
              "Maker cannot authorize the record",
              ""
            );
          }
        }
      });
  }
  onSubmitEditMaintenance() {
    this.editFlag = true;
    console.log(this.editFlag);
  }

  onClosingTheRecord() {
    console.log("this is close");
    this.departmentService
      .onCloseOfDepartment(this.departmentForm.value)
      .subscribe((closeResp) => {
        console.log(closeResp);
        this.respData = closeResp;
        if (this.respData) {
          if (this.respData.verifiedStatus == "U") {
            this.toastService.errorMessage(
              "Unauthorize Record Cannot be Closed",
              ""
            );
          } else {
            this.toastService.successMessage(
              "Record closed succefully",
              ""
              // type: "success"
            );
          }
        }
      });
  }

  onReopningTheRecord() {
    console.log("this is reopen");
    this.departmentService
      .onReopenOfDepartment(this.departmentForm.value)
      .subscribe((reopnResp) => {
        console.log(reopnResp);
        this.respData = reopnResp;
        if (this.respData) {
          if (this.respData.recordStatus == "O") {
            this.toastService.successMessage(
              "Record opened succefully",
              ""
              // type: "success"
            );
          } else {
            this.toastService.errorMessage("Record cannot be opened ", "");
          }
        }
      });
  }
  onDeletingTheRecord() {
    console.log("this is delete");
    this.departmentService
      .onDeleteOfDepartment(this.departmentForm.value)
      .subscribe((deleteResp) => {
        console.log(deleteResp);
        this.respData = deleteResp;
        if (this.respData) {
  
          if (this.respData.chargeAmount == null) {
            this.toastService.successMessage(
              "Record deleted succefully",
              ""
              // type: "success"
            );
          } else {
            this.toastService.errorMessage("Record cannot be Deleted ", "");
          }
        }
      });
  }
  numericOnly(event): boolean {
    return !isNaN(Number(event.key)) && event.key !== " ";
  }
}
